import{_ as o,o as a,c as r,a3 as e}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"文本差异对比","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/text-diff.md","filePath":"user-guide/tools/text-diff.md","lastUpdated":1778221347000}'),d={name:"user-guide/tools/text-diff.md"};function i(n,t,s,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="文本差异对比" tabindex="-1">文本差异对比 <a class="header-anchor" href="#文本差异对比" aria-label="Permalink to &quot;文本差异对比&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>文本差异对比工具提供了一个专业且直观的文件对比环境，基于 Monaco Editor 的差异对比引擎，让你能够快速发现两个文件或两段文本之间的细微差异。无论是代码审查、配置文件比对，还是文档版本对比，它都能胜任。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>可视化差异引擎</strong>：基于 Monaco Diff Editor，支持逐行对比与字符级差异高亮，差异点清晰标注增删改</li><li><strong>智能文件拖放</strong>：拖入一个文件自动填充空侧，拖入两个文件自动分配到左右两侧，减少操作步骤</li><li><strong>并排/内联双模式</strong>：支持并排对比和内联统一视图两种布局，适应不同的审阅习惯</li><li><strong>差异导航与计数</strong>：自动统计差异总数，支持上一处/下一处快速跳转，大型文件也不迷路</li><li><strong>Unified Diff 补丁导出</strong>：一键生成标准统一 Diff 格式（<code>.patch</code>）补丁文件，与 Git 等版本控制工具无缝对接</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-4-步走" tabindex="-1">首次使用 4 步走 <a class="header-anchor" href="#首次使用-4-步走" aria-label="Permalink to &quot;首次使用 4 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>文本差异对比</strong>，点击进入。你将看到一个左右分区界面，顶部是功能丰富的工具栏，中间是一个空白对比编辑器。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注工具栏、左右编辑器区域和文件名显示区域</p></blockquote><p><strong>第二步：准备对比内容</strong></p><p>有四种方式向编辑器填入内容：</p><table tabindex="0"><thead><tr><th>方式</th><th>操作说明</th></tr></thead><tbody><tr><td><strong>直接键入</strong></td><td>在左右编辑器中直接输入或粘贴文本</td></tr><tr><td><strong>拖拽文件</strong></td><td>将一个文件拖到编辑器区域自动分配到空侧，或同时拖入两个文件自动分配</td></tr><tr><td><strong>从文件打开</strong></td><td>点击工具栏的 <strong>文件 → 打开左侧 / 打开右侧</strong> 选择本地文件</td></tr><tr><td><strong>从剪贴板粘贴</strong></td><td>点击工具栏的 <strong>剪贴板 → 粘贴到左侧 / 粘贴到右侧</strong></td></tr></tbody></table><blockquote><p>💡 <strong>最快捷的方式</strong>：同时选中两个文件，一起拖入编辑器区域，工具会自动将它们分配到左右两侧，并自动识别语言类型提供语法高亮。</p></blockquote><blockquote><p>TODO: 截图 - 拖拽两个文件到编辑器区域的效果，标注文件名显示区域显示的左右文件名</p></blockquote><p><strong>第三步：查看差异</strong></p><p>内容填入后，Monaco Diff Editor 会自动开始比对。差异点会以不同颜色高亮显示：</p><ul><li><strong>红色背景</strong>：表示左侧独有（删除的内容）</li><li><strong>绿色背景</strong>：表示右侧独有（新增的内容）</li><li><strong>左侧行号区域的红色/绿色标记</strong>：快速定位差异行</li></ul><p>右上角的差异导航区域会显示 <code>1 / 5</code> 这样的计数，表明共有 5 处差异，当前在第 1 处。</p><blockquote><p>TODO: 截图 - 对比结果，标注红色（删除）、绿色（新增）和差异导航计数器</p></blockquote><p><strong>第四步：导航与导出</strong></p><p>使用工具栏的 <strong>上一处 / 下一处</strong> 按钮在各个差异点之间跳转，快速审阅每一处变更。审阅完成后：</p><ul><li><strong>复制补丁</strong>：点击 <strong>剪贴板 → 复制补丁</strong>，将标准 Unified Diff 格式复制到剪贴板</li><li><strong>导出 .patch</strong>：点击 <strong>文件 → 导出 .patch</strong>，保存为补丁文件供版本控制使用</li></ul><blockquote><p>TODO: 截图 - 工具栏的差异导航按钮和文件导出菜单</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><p>工具栏分为多个功能区，从上到下依次是语言选择、布局切换、比对选项、差异导航和操作按钮。</p><h4 id="语言选择" tabindex="-1">语言选择 <a class="header-anchor" href="#语言选择" aria-label="Permalink to &quot;语言选择&quot;">​</a></h4><p>工具栏左侧是一个 <strong>语言选择下拉框</strong>（默认自动检测）。当通过文件打开或拖拽加载文件时，系统会根据文件后缀自动推断语言类型（如 <code>.ts</code> 对应 TypeScript、<code>.py</code> 对应 Python），你也可以手动切换以改变语法高亮。</p><p>支持的语言包括：纯文本、JavaScript、TypeScript、JSON、HTML、CSS、Python、Java、C++、Markdown。</p><blockquote><p>TODO: 截图 - 语言选择下拉框展开状态</p></blockquote><h4 id="布局切换-并排-vs-内联" tabindex="-1">布局切换：并排 vs 内联 <a class="header-anchor" href="#布局切换-并排-vs-内联" aria-label="Permalink to &quot;布局切换：并排 vs 内联&quot;">​</a></h4><p>工具栏提供两个布局模式的切换按钮：</p><table tabindex="0"><thead><tr><th>模式</th><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>并排</strong>（默认）</td><td><code>并排</code> 按钮</td><td>左侧显示原文本，右侧显示修改后文本，差异点高亮对应显示</td></tr><tr><td><strong>内联</strong></td><td><code>内联</code> 按钮</td><td>所有内容显示在同一区域，差异点以行内标记形式呈现</td></tr></tbody></table><p><strong>内联模式</strong>更适合读不太长的内容，可以纵向滚动查看整体变更脉络而不需要左右对照。</p><blockquote><p>TODO: 截图 - 同一份内容分别在并排和内联模式下的效果对比</p></blockquote><h4 id="比对选项" tabindex="-1">比对选项 <a class="header-anchor" href="#比对选项" aria-label="Permalink to &quot;比对选项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><strong>忽略行尾空白</strong></td><td>默认开启。忽略每行末尾的空白字符差异（空格、制表符），专注于代码逻辑的变更</td></tr><tr><td><strong>只看变更</strong></td><td>开启后，差异化区域高亮着色消失，右侧的变更概览条隐藏，适合关注无差异状态的终版结果</td></tr><tr><td><strong>自动换行</strong></td><td>开启后长行自动折行显示，无需水平滚动</td></tr><tr><td><strong>忽略大小写</strong></td><td>⚠️ <strong>实验性功能</strong>。开启后差异计数会忽略大小写差异，但不改变可视高亮的差异区域</td></tr></tbody></table><blockquote><p>TODO: 截图 - 工具栏的四个比对选项复选框</p></blockquote><h4 id="差异导航" tabindex="-1">差异导航 <a class="header-anchor" href="#差异导航" aria-label="Permalink to &quot;差异导航&quot;">​</a></h4><p>工具栏中间区域提供差异导航控件：</p><table tabindex="0"><thead><tr><th>控件</th><th>说明</th></tr></thead><tbody><tr><td><strong>上一处</strong> 按钮</td><td>跳转到上一处差异，编辑器自动滚动到对应位置</td></tr><tr><td><strong>下一处</strong> 按钮</td><td>跳转到下一处差异</td></tr><tr><td><strong>差异计数</strong></td><td>显示 <code>当前索引 / 总数</code>（如 <code>3 / 12</code>），无差异时显示 <code>无差异</code></td></tr></tbody></table><p>当差异总数为 0 时，导航按钮会自动禁用（灰色不可点击）。</p><blockquote><p>TODO: 截图 - 差异导航按钮组和计数器</p></blockquote><h4 id="文件操作菜单" tabindex="-1">文件操作菜单 <a class="header-anchor" href="#文件操作菜单" aria-label="Permalink to &quot;文件操作菜单&quot;">​</a></h4><p>点击 <strong>文件</strong> 按钮展开下拉菜单：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>打开左侧</strong></td><td>系统文件对话框中选择文件，加载到左侧编辑器</td></tr><tr><td><strong>打开右侧</strong></td><td>同上，加载到右侧编辑器</td></tr><tr><td><strong>保存左侧</strong></td><td>将左侧编辑器中修改后的内容保存到文件</td></tr><tr><td><strong>保存右侧</strong></td><td>将右侧编辑器中修改后的内容保存到文件</td></tr><tr><td><strong>保存两侧</strong></td><td>同时保存左右两侧</td></tr><tr><td><strong>导出 .patch</strong></td><td>生成 Unified Diff 补丁并保存为 <code>.patch</code> 文件（默认文件名：<code>文件名A_vs_文件名B.patch</code>）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 文件下拉菜单展开</p></blockquote><h4 id="剪贴板操作菜单" tabindex="-1">剪贴板操作菜单 <a class="header-anchor" href="#剪贴板操作菜单" aria-label="Permalink to &quot;剪贴板操作菜单&quot;">​</a></h4><p>点击 <strong>剪贴板</strong> 按钮展开下拉菜单：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制左侧</strong></td><td>将左侧编辑器内容复制到系统剪贴板</td></tr><tr><td><strong>复制右侧</strong></td><td>将右侧编辑器内容复制到系统剪贴板</td></tr><tr><td><strong>复制补丁</strong></td><td>将生成的 Unified Diff 补丁复制到剪贴板（格式与导出相同但不保存文件）</td></tr><tr><td><strong>粘贴到左侧</strong></td><td>将系统剪贴板中的文本粘贴到左侧编辑器</td></tr><tr><td><strong>粘贴到右侧</strong></td><td>将系统剪贴板中的文本粘贴到右侧编辑器</td></tr></tbody></table><blockquote><p>TODO: 截图 - 剪贴板下拉菜单展开</p></blockquote><h4 id="清空与交换" tabindex="-1">清空与交换 <a class="header-anchor" href="#清空与交换" aria-label="Permalink to &quot;清空与交换&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>清空</strong> 下拉</td><td>可选择清空左侧、右侧或两侧全部内容</td></tr><tr><td><strong>交换</strong> 按钮</td><td>一键交换左右两侧的内容和文件名，快速切换对比方向（如交换原文本和修改后文本的位置）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 清空下拉菜单和交换按钮</p></blockquote><h3 id="文件名显示区域" tabindex="-1">文件名显示区域 <a class="header-anchor" href="#文件名显示区域" aria-label="Permalink to &quot;文件名显示区域&quot;">​</a></h3><p>编辑器上方有一个文件名显示栏，左右各占一半。当通过文件加载时，会显示对应的文件名和文件图标；未加载文件时显示占位文字（<code>左侧：未命名</code> / <code>右侧：未命名</code>）。</p><p>在编辑过程中直接修改编辑器内容不会影响文件名显示，保存文件后会更新文件名。</p><blockquote><p>TODO: 截图 - 文件名显示区域，左侧显示 &quot;app.ts&quot;，右侧显示 &quot;app_v2.ts&quot;</p></blockquote><h3 id="差异编辑器" tabindex="-1">差异编辑器 <a class="header-anchor" href="#差异编辑器" aria-label="Permalink to &quot;差异编辑器&quot;">​</a></h3><p>编辑器区域是整个工具的核心，它使用 <code>RichCodeEditor</code> 组件的 Monaco Editor Diff 模式。关键特性：</p><ul><li><strong>左侧编辑器可编辑</strong>：你可以直接在左侧（原文本）编辑器中修改内容，对比结果会实时更新。这在快速尝试不同修改方案时非常有用。</li><li><strong>自动语言识别</strong>：通过文件后缀自动推断语法高亮语言（如 <code>.ts</code> → TypeScript）</li><li><strong>大文件警告</strong>：加载超过 10MB 的文件时会提示&quot;文件较大，可能影响性能&quot;</li><li><strong>二进制文件检测</strong>：如果拖入或打开的是一个二进制文件，工具会自动检测并拒绝加载，提示&quot;不支持二进制文件&quot;</li></ul><h4 id="左侧拖放区域-右侧拖放区域" tabindex="-1">左侧拖放区域 / 右侧拖放区域 <a class="header-anchor" href="#左侧拖放区域-右侧拖放区域" aria-label="Permalink to &quot;左侧拖放区域 / 右侧拖放区域&quot;">​</a></h4><p>编辑器区域左右两侧各有一个透明的文件拖放感应区。当你拖拽文件到对应位置时，感应区会浮现蓝色虚线边框和提示文字，松开后文件自动加载到对应侧的编辑器。</p><blockquote><p>💡 <strong>智能分配逻辑</strong>：</p><ul><li>拖入 <strong>两个文件</strong>：自动分配到左右两侧</li><li>拖入 <strong>一个文件</strong>：如果有一侧为空，自动填充到空侧；如果两侧都有内容，覆盖鼠标指向的那一侧</li></ul></blockquote><blockquote><p>TODO: 截图 - 拖拽文件到左侧区域时出现的蓝色虚线边框和&quot;拖放文件到左侧&quot;提示</p></blockquote><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="代码审查工作流" tabindex="-1">代码审查工作流 <a class="header-anchor" href="#代码审查工作流" aria-label="Permalink to &quot;代码审查工作流&quot;">​</a></h3><p><strong>场景</strong>：你在 Code Review 时需要对两个版本的代码进行逐行对比。</p><ol><li>同时选中 <code>main.ts</code> 和 <code>feature.ts</code> 拖入编辑器</li><li>使用 <strong>下一处</strong> 按钮逐项审查差异</li><li>如果发现某处修改不合理，直接在左侧编辑器中修改回原样</li><li>审查完成后，点击 <strong>文件 → 保存左侧</strong> 将修正后的文件保存</li><li>如需记录变更历史，点击 <strong>文件 → 导出 .patch</strong> 保存补丁文件</li></ol><h3 id="合并冲突手动解析" tabindex="-1">合并冲突手动解析 <a class="header-anchor" href="#合并冲突手动解析" aria-label="Permalink to &quot;合并冲突手动解析&quot;">​</a></h3><p><strong>场景</strong>：合并分支时出现冲突，可以用文本差异对比辅助理解冲突内容。</p><ol><li>在 Git 中查看冲突文件后，将&quot;我们&quot;的版本和&quot;他们&quot;的版本分别复制到左右编辑器</li><li>开启 <strong>忽略行尾空白</strong> 避免无关差异干扰</li><li>逐处审查差异点，确定哪些变更需要保留</li><li>在左侧或右侧编辑器中直接编辑合并结果</li><li>存入合并后的文件</li></ol><h3 id="使用补丁文件与-git-集成" tabindex="-1">使用补丁文件与 Git 集成 <a class="header-anchor" href="#使用补丁文件与-git-集成" aria-label="Permalink to &quot;使用补丁文件与 Git 集成&quot;">​</a></h3><p>生成的 <code>.patch</code> 文件是标准 Unified Diff 格式，可以与 Git 搭配使用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应用补丁（在 Git 仓库中）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-diff.patch</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看补丁预览</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-diff.patch</span></span></code></pre></div><p>这在以下场景特别有用：</p><ul><li>你想对比两个文件后，将差异以补丁形式分享给团队</li><li>需要在不直接提交代码的情况下，将变更应用到其他分支</li></ul><h3 id="快捷键-monaco-editor-内置" tabindex="-1">快捷键（Monaco Editor 内置） <a class="header-anchor" href="#快捷键-monaco-editor-内置" aria-label="Permalink to &quot;快捷键（Monaco Editor 内置）&quot;">​</a></h3><p>由于编辑器基于 Monaco Editor，你可以使用许多熟悉的快捷键：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+F</code></td><td>在当前编辑器中搜索</td></tr><tr><td><code>Ctrl+H</code></td><td>替换文本</td></tr><tr><td><code>Ctrl+Z</code></td><td>撤销修改</td></tr><tr><td><code>Ctrl+Shift+Z</code></td><td>重做修改</td></tr><tr><td><code>Alt+↑/↓</code></td><td>上下移动行</td></tr></tbody></table><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么拖拽文件后没有自动对比" tabindex="-1">Q：为什么拖拽文件后没有自动对比？ <a class="header-anchor" href="#q-为什么拖拽文件后没有自动对比" aria-label="Permalink to &quot;Q：为什么拖拽文件后没有自动对比？&quot;">​</a></h3><p>检查一下文件是否成功加载——观察文件名显示区域是否出现了文件名，以及编辑器中是否显示了文件内容。如果文件名区域显示&quot;未命名&quot;，说明文件没有成功加载。可能的原因：</p><ul><li>文件是二进制类型（如图片、压缩包），工具会自动拒绝并提示&quot;不支持二进制文件&quot;</li><li>文件路径包含特殊字符或权限不足，请尝试使用 <strong>文件 → 打开左侧/右侧</strong> 通过系统对话框加载</li></ul><h3 id="q-为何差异计数和实际看到的差异颜色数量不一致" tabindex="-1">Q：为何差异计数和实际看到的差异颜色数量不一致？ <a class="header-anchor" href="#q-为何差异计数和实际看到的差异颜色数量不一致" aria-label="Permalink to &quot;Q：为何差异计数和实际看到的差异颜色数量不一致？&quot;">​</a></h3><p>差异计数依赖于 Monaco Editor 的 <code>getLineChanges()</code> 接口，它按连续的差异行块计数。一个&quot;差异&quot;可能包含多行增删改。另外，<strong>忽略大小写</strong>选项（实验性功能）会影响计数但不影响可视高亮的差异区域，所以计数可能低于实际可视的差异块。</p><h3 id="q-左侧编辑器修改了内容-差异会实时更新吗" tabindex="-1">Q：左侧编辑器修改了内容，差异会实时更新吗？ <a class="header-anchor" href="#q-左侧编辑器修改了内容-差异会实时更新吗" aria-label="Permalink to &quot;Q：左侧编辑器修改了内容，差异会实时更新吗？&quot;">​</a></h3><p>会的。<code>originalEditable: true</code> 配置使左侧（原文本）编辑器可直接编辑，每次输入后 Monaco Editor 会重新计算差异，差异导航计数也会同步更新。这让你可以在看到差异后直接在原文本上修改，快速尝试不同方案。</p><h3 id="q-导出的-patch-文件怎么用" tabindex="-1">Q：导出的 .patch 文件怎么用？ <a class="header-anchor" href="#q-导出的-patch-文件怎么用" aria-label="Permalink to &quot;Q：导出的 .patch 文件怎么用？&quot;">​</a></h3><p>导出的补丁是标准 Unified Diff 格式，包含文件名、上下文行和差异标记。你可以：</p><ul><li>用文本编辑器打开查看内容</li><li>通过 <code>git apply</code> 命令应用到 Git 仓库</li><li>发送给同事供 Code Review</li></ul><p>工具默认的上下文行数为 3 行（标准 Git Diff 默认值），补丁头部包含原文件名和新文件名信息。</p><h3 id="q-对比大文件-超过-10mb-时卡顿怎么办" tabindex="-1">Q：对比大文件（超过 10MB）时卡顿怎么办？ <a class="header-anchor" href="#q-对比大文件-超过-10mb-时卡顿怎么办" aria-label="Permalink to &quot;Q：对比大文件（超过 10MB）时卡顿怎么办？&quot;">​</a></h3><p>加载超过 10MB 的文件时，工具会提示&quot;文件较大，可能影响性能&quot;。此时建议：</p><ul><li>关闭 <strong>只看变更</strong> 和 <strong>自动换行</strong> 选项，减少渲染开销</li><li>使用 <strong>内联模式</strong> 替代并排模式，节省编辑器的渲染资源</li><li>如果文件大小超过 100MB，建议使用专业的文件对比工具（如 Beyond Compare）</li><li>只对比文件中有意义的部分，而非整个文件</li></ul><h3 id="q-两侧内容完全相同但导航显示有差异" tabindex="-1">Q：两侧内容完全相同但导航显示有差异？ <a class="header-anchor" href="#q-两侧内容完全相同但导航显示有差异" aria-label="Permalink to &quot;Q：两侧内容完全相同但导航显示有差异？&quot;">​</a></h3><p>检查 <strong>忽略行尾空白</strong> 选项是否关闭。如果关闭，行尾多余的空白字符（空格、制表符）会被视为差异。建议大多数情况下保持此选项开启。另外，Windows 换行符（CRLF）和 Unix 换行符（LF）的差异也可能导致显示差异——工具目前不会自动忽略换行符差异。</p>`,98)])])}const u=o(d,[["render",i]]);export{g as __pageData,u as default};
